import assert from "node:assert/strict";
import test from "node:test";

import {
  DOCUMENT_PREVIEW_IFRAME_SANDBOX,
  PDF_PREVIEW_IFRAME_SANDBOX,
  PREVIEW_IFRAME_REFERRER_POLICY,
  getSandboxedPreviewIframeProps,
  resolveSafeInlineIframePreviewUrl,
} from "./iframe-preview";

test("resolveSafeInlineIframePreviewUrl limits inline previews to trusted same-origin content", () => {
  assert.equal(
    resolveSafeInlineIframePreviewUrl("/dev/mail-preview/example", {
      baseUrl: "https://sqr-system.com/current",
    }),
    "https://sqr-system.com/dev/mail-preview/example",
  );
  assert.equal(
    resolveSafeInlineIframePreviewUrl("https://preview.example.test/receipt.pdf", {
      baseUrl: "https://sqr-system.com/current",
    }),
    null,
  );
  assert.equal(
    resolveSafeInlineIframePreviewUrl("blob:https://sqr-system.com/receipt-id", {
      baseUrl: "https://sqr-system.com/current",
    }),
    null,
  );
  assert.equal(
    resolveSafeInlineIframePreviewUrl("blob:https://sqr-system.com/receipt-id", {
      allowBlob: true,
      baseUrl: "https://sqr-system.com/current",
    }),
    "blob:https://sqr-system.com/receipt-id",
  );
});

test("getSandboxedPreviewIframeProps keeps preview frames locked down by content type", () => {
  assert.equal(DOCUMENT_PREVIEW_IFRAME_SANDBOX, "");
  assert.equal(PDF_PREVIEW_IFRAME_SANDBOX, "allow-downloads allow-same-origin allow-scripts");
  assert.equal(PREVIEW_IFRAME_REFERRER_POLICY, "no-referrer");

  assert.deepEqual(getSandboxedPreviewIframeProps("document"), {
    referrerPolicy: "no-referrer",
    sandbox: "",
  });
  assert.deepEqual(getSandboxedPreviewIframeProps("pdf"), {
    referrerPolicy: "no-referrer",
    sandbox: "allow-downloads allow-same-origin allow-scripts",
  });
});

import type { IframeHTMLAttributes } from "react";

import { resolveSafePreviewSourceUrl } from "@/lib/safe-url";

export const DOCUMENT_PREVIEW_IFRAME_SANDBOX = "";
export const PDF_PREVIEW_IFRAME_SANDBOX = "allow-downloads allow-same-origin allow-scripts";
export const PREVIEW_IFRAME_REFERRER_POLICY: IframeHTMLAttributes<HTMLIFrameElement>["referrerPolicy"] =
  "no-referrer";

type ResolveSafeInlineIframePreviewUrlOptions = {
  baseUrl?: string | URL;
  allowBlob?: boolean;
};

export function resolveSafeInlineIframePreviewUrl(
  value: string | null | undefined,
  { baseUrl, allowBlob = false }: ResolveSafeInlineIframePreviewUrlOptions = {},
): string | null {
  const safeSource = resolveSafePreviewSourceUrl(
    value,
    baseUrl === undefined
      ? { allowBlob }
      : {
          allowBlob,
          baseUrl,
        },
  );

  if (!safeSource) {
    return null;
  }

  if (safeSource.startsWith("blob:") && !allowBlob) {
    return null;
  }

  return safeSource;
}

export function getSandboxedPreviewIframeProps(
  kind: "document" | "pdf",
): Pick<IframeHTMLAttributes<HTMLIFrameElement>, "referrerPolicy" | "sandbox"> {
  return {
    referrerPolicy: PREVIEW_IFRAME_REFERRER_POLICY,
    sandbox:
      kind === "pdf"
        ? PDF_PREVIEW_IFRAME_SANDBOX
        : DOCUMENT_PREVIEW_IFRAME_SANDBOX,
  };
}

const SAFE_URL_BASE_FALLBACK = "https://app.sqr.invalid";

type ResolveSafeUrlOptions = {
  allowedProtocols?: readonly string[];
  baseUrl?: string | URL;
  sameOriginOnly?: boolean;
};

type ResolveSafePreviewUrlOptions = {
  baseUrl?: string | URL;
  allowBlob?: boolean;
};

function normalizeUrlValue(value: string | null | undefined): string {
  return String(value || "").trim();
}

function resolveUrlBase(baseUrl?: string | URL): URL {
  if (baseUrl instanceof URL) {
    return baseUrl;
  }

  const normalizedBaseUrl = normalizeUrlValue(baseUrl);
  if (normalizedBaseUrl) {
    return new URL(normalizedBaseUrl);
  }

  if (typeof window !== "undefined" && window.location?.href) {
    return new URL(window.location.href);
  }

  return new URL(SAFE_URL_BASE_FALLBACK);
}

export function resolveSafeUrl(
  value: string | null | undefined,
  {
    allowedProtocols = ["http:", "https:"],
    baseUrl,
    sameOriginOnly = false,
  }: ResolveSafeUrlOptions = {},
): string | null {
  const normalizedValue = normalizeUrlValue(value);
  if (!normalizedValue) {
    return null;
  }

  const resolvedBase = resolveUrlBase(baseUrl);
  const allowedProtocolSet = new Set(
    allowedProtocols.map((protocol) => String(protocol).trim().toLowerCase()).filter(Boolean),
  );

  try {
    const resolvedUrl = new URL(normalizedValue, resolvedBase);
    const normalizedProtocol = resolvedUrl.protocol.toLowerCase();

    if (!allowedProtocolSet.has(normalizedProtocol)) {
      return null;
    }

    if (sameOriginOnly && resolvedUrl.origin !== resolvedBase.origin) {
      return null;
    }

    return resolvedUrl.toString();
  } catch {
    return null;
  }
}

export function resolveSafeHttpUrl(
  value: string | null | undefined,
  options: Omit<ResolveSafeUrlOptions, "allowedProtocols"> = {},
): string | null {
  return resolveSafeUrl(value, {
    ...options,
    allowedProtocols: ["http:", "https:"],
  });
}

export function resolveSafeNavigationUrl(
  value: string | null | undefined,
  options: Omit<ResolveSafeUrlOptions, "allowedProtocols" | "sameOriginOnly"> = {},
): string | null {
  return resolveSafeUrl(value, {
    ...options,
    allowedProtocols: ["http:", "https:"],
    sameOriginOnly: true,
  });
}

export function resolveSafePreviewSourceUrl(
  value: string | null | undefined,
  { baseUrl, allowBlob = true }: ResolveSafePreviewUrlOptions = {},
): string | null {
  const normalizedValue = normalizeUrlValue(value);
  if (!normalizedValue) {
    return null;
  }

  const resolvedBase = resolveUrlBase(baseUrl);
  const allowedProtocols = allowBlob
    ? new Set(["http:", "https:", "blob:"])
    : new Set(["http:", "https:"]);

  try {
    const resolvedUrl = new URL(normalizedValue, resolvedBase);
    const normalizedProtocol = resolvedUrl.protocol.toLowerCase();

    if (!allowedProtocols.has(normalizedProtocol)) {
      return null;
    }

    if (resolvedUrl.origin !== resolvedBase.origin) {
      return null;
    }

    return resolvedUrl.toString();
  } catch {
    return null;
  }
}
